 25→const Editor=({onClose, initialTitle = '', promptId = null, promptText = null, draftId = null, draftContent = null}) =>{
 26→    const {session} = useAuth();
 27→    const queryClient = useQueryClient();
 28→
 29→    const [title, setTitle] = useState(initialTitle || '')
 30→    const [wordCount, setWordCount] = useState(0);
 31→    const [editor] = useLexicalComposerContext();
 32→    const currentDraftIdRef = useRef(draftId);
 33→    const editorStateRef = useRef({ hasChanges: false, hasContent: false, editorState: null, title: '' });
 34→    const [showCloseConfirm, setShowCloseConfirm] = useState(false);
 35→    const [isSavingDraft, setIsSavingDraft] = useState(false);
 36→    const [saveError, setSaveError] = useState(false);
 37→    const saveButtonRef = useRef(null);
 38→    const isClosingRef = useRef(false);
 39→
 40→    const [uploadedImagePaths, setUploadedImagePaths] = useState([]);
 41→
 42→    const addUploadedImagePath = useCallback((imagePath) =>{
 43→      setUploadedImagePaths((prev) => [...prev, imagePath]);
 44→    }, [])
 45→
 46→    useEffect(() => {
 47→        setTitle(initialTitle || '');
 48→    }, [initialTitle]);
 49→
 50→    // Load draft content into Lexical editor on mount
 51→    useEffect(() => {
 52→        if (draftContent && editor) {
 53→            try {
 54→                const parsedState = editor.parseEditorState(draftContent);
 55→                editor.setEditorState(parsedState);
 56→            } catch (err) {
 57→                console.error('Failed to load draft content:', err);
 58→            }
 59→        }
 60→    }, [draftContent, editor]);
 61→
 62→    const handleDraftIdCreated = useCallback((newDraftId) => {
 63→        currentDraftIdRef.current = newDraftId;
 64→    }, []);
 65→
 66→    const handleCloseEditor = useCallback(async() => {
 67→      // Only delete uploaded images if there's no saved draft
 68→      // (drafts own their images)
 69→      if(uploadedImagePaths.length > 0 && !currentDraftIdRef.current){
 70→        const message = await deleteJournalImage(session?.access_token, uploadedImagePaths)
 71→        if(message){
 72→          // console.log(message.message)
 73→        }
 74→      }
 75→
 76→        editor.update(() => {
 77→            const root = $getRoot();
 78→            root.clear();
 79→            onClose();
 80→        })
 81→    }, [editor, onClose, session?.access_token, uploadedImagePaths])
 82→
 83→    const handleCloseEditorOnSave = useCallback(async() => {
 84→      editor.update(() => {
 85→            const root = $getRoot();
 86→            root.clear();
 87→            onClose();
 88→      })
 89→    }, [onClose, editor])
 90→
 91→    const handleCloseClick = useCallback(() => {
 92→        if (isClosingRef.current) return;
 93→        const { hasChanges, hasContent } = editorStateRef.current;
 94→        if (hasChanges && hasContent) {
 95→            setShowCloseConfirm(true);
 96→        } else {
 97→            isClosingRef.current = true;
 98→            handleCloseEditor();
 99→        }
100→    }, [handleCloseEditor])
101→
102→    const handleConfirmSaveDraft = useCallback(async () => {
103→        let currentEditorState;
104→        editor.read(() => {
105→            currentEditorState = JSON.stringify(editor.getEditorState().toJSON());
106→        });
107→        if (!currentEditorState || !session?.access_token) {
108→            handleCloseEditor();
109→            return;
110→        }
111→        setSaveError(false);
112→        setIsSavingDraft(true);
113→
114→        // Cancel pending auto-save timer
115→        if (editorStateRef.current.saveTimerRef) {
116→            clearTimeout(editorStateRef.current.saveTimerRef.current);
117→        }
118→
119→        try {
120→            await saveDraft(session.access_token, {
121→                content: currentEditorState,
122→                title: title || '',
123→                draftId: currentDraftIdRef.current || null,
